from django.contrib.auth.models import User
from django.shortcuts import redirect, render
from django.views.decorators.csrf import csrf_exempt
from xml.etree.ElementTree import ElementTree, fromstring
from urllib.parse import parse_qs
import base64
import logging

logger = logging.getLogger(__name__)

@csrf_exempt
def saml_acs(request):
    if request.method == 'POST':
        encoded_saml_response = parse_qs(request.body.decode('utf-8'))['SAMLResponse'][0]
        decoded_saml_response = base64.b64decode(encoded_saml_response).decode('utf-8')

        # Basic XML structure validation
        try:
            root = ElementTree(fromstring(decoded_saml_response))
        except Exception as e:
            logger.error(f"Invalid SAML response: {e}")
            return render(request, 'error.html', {'message': 'Invalid SAML Response'})

        # Extracting user information from assertion attributes
        name_id_element = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}NameID')
        if not name_id_element:
            logger.error("NameID element not found in the SAML response")
            return render(request, 'error.html', {'message': 'NameID Element Missing'})

        name_id = name_id_element.text
        user_attributes = {}
        attribute_statement = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeStatement')
        if attribute_statement:
            for attr in attribute_statement.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
                attr_name = attr.get('Name')
                attr_values = [value.text for value in attr.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue')]
                user_attributes[attr_name] = attr_values

        # Creating or updating Django user session
        try:
            user, created = User.objects.get_or_create(username=name_id)
            if not user.is_active:
                user.is_active = True
                user.save()

            for key, values in user_attributes.items():
                setattr(user, key.lower(), ', '.join(values))
            user.save()

            request.session['user'] = name_id
            return redirect('home')

        except Exception as e:
            logger.error(f"Error processing SAML response: {e}")
            return render(request, 'error.html', {'message': 'Error Processing Response'})

    else:
        return render(request, 'error.html', {'message': 'Invalid Request Method'})